import{bQ as e,aL as a,u as s,G as d}from"./chunks/framework.D06dwy5q.js";const k=JSON.parse('{"title":"03｜数据类型与约束","description":"","frontmatter":{},"headers":[],"relativePath":"04.MySQL/03-数据类型与约束.md","filePath":"04.MySQL/03-数据类型与约束.md","lastUpdated":null}'),i={name:"04.MySQL/03-数据类型与约束.md"};function o(h,t,l,n,p,c){return a(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="_03-数据类型与约束" tabindex="-1">03｜数据类型与约束 <a class="header-anchor" href="#_03-数据类型与约束" aria-label="Permalink to &quot;03｜数据类型与约束&quot;">​</a></h1><p>上一篇建了一张 servers 表，字段类型是照着写的。但为什么 id 用 <code>BIGINT</code> 不用 <code>INT</code>？为什么 IP 用 <code>VARCHAR(45)</code> 不用 <code>VARCHAR(255)</code>？金额为什么不能存 <code>FLOAT</code>？</p><p>这些选择不是随便定的。字段类型定下来后，存储空间、索引效果、查询行为都跟着定了。<strong>改字段类型在线上是重操作</strong>（大表要拷贝数据），建表时尽量一次选对。本篇讲常见类型怎么选、约束怎么用。</p><h2 id="一、整数类型" tabindex="-1">一、整数类型 <a class="header-anchor" href="#一、整数类型" aria-label="Permalink to &quot;一、整数类型&quot;">​</a></h2><p>存 ID、计数、状态码这类整数，按值的范围选：</p><table tabindex="0"><thead><tr><th>类型</th><th>范围</th><th>适合</th></tr></thead><tbody><tr><td><code>TINYINT</code></td><td>-128~127（或 0~255 UNSIGNED）</td><td>状态码、布尔标志</td></tr><tr><td><code>INT</code></td><td>约 ±21 亿</td><td>一般计数、中等表的 ID</td></tr><tr><td><code>BIGINT</code></td><td>约 ±9.2×10¹⁸</td><td>大表 ID、自增主键</td></tr></tbody></table><p>一个常见做法：主键用 <code>BIGINT UNSIGNED AUTO_INCREMENT</code>。<code>UNSIGNED</code> 让值翻倍（只用正数，ID 本来就不要负数），自增主键增长到很大的表用 INT 可能不够。</p><p>别图省事全用 <code>BIGINT</code>——存个状态码用 BIGINT 浪费空间，索引也更大更慢。按实际范围选最小的够用的类型。</p><h2 id="二、小数-金额不能用-float" tabindex="-1">二、小数：金额不能用 FLOAT <a class="header-anchor" href="#二、小数-金额不能用-float" aria-label="Permalink to &quot;二、小数：金额不能用 FLOAT&quot;">​</a></h2><p>存金额、需要精确的小数，用 <code>DECIMAL</code>，不要用 <code>FLOAT</code>/<code>DOUBLE</code>：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">price </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DECIMAL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 总共 10 位，小数 2 位</span></span></code></pre></div><p>为什么？<code>FLOAT</code> 是浮点数，有精度误差。<code>0.1 + 0.2</code> 在浮点里可能等于 <code>0.30000000000000004</code>。算账时差一分钱都是问题。<code>DECIMAL</code> 是定点数，存什么就是什么，没有误差。</p><p>金额场景 <code>DECIMAL(10,2)</code> 够大部分情况（最大 99999999.99）。要求更高的用更大精度。</p><h2 id="三、字符串类型" tabindex="-1">三、字符串类型 <a class="header-anchor" href="#三、字符串类型" aria-label="Permalink to &quot;三、字符串类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>适用</th><th>注意</th></tr></thead><tbody><tr><td><code>VARCHAR(N)</code></td><td>变长字符串（主机名、IP、名字）</td><td>按业务上限估长度</td></tr><tr><td><code>CHAR(N)</code></td><td>定长字符串（固定编码、hash）</td><td>不足 N 自动补空格</td></tr><tr><td><code>TEXT</code></td><td>长文本（文章内容、日志）</td><td>不能有默认值，索引要前缀</td></tr></tbody></table><p><code>VARCHAR</code> 最常用。关键点是<strong>长度按业务实际上限估，别全写 255</strong>。</p><p>为什么别都写 255？一方面浪费——存 32 字节的 IP 写 255，索引按声明长度分配内存。另一方面误导——读代码的人以为这字段最长 255，实际业务只到 45。按真实上限（IP 用 45、主机名用 128）声明，更准确。</p><p><code>TEXT</code> 用于存很长的内容，但它不能设默认值，建索引要指定前缀长度（<code>KEY(字段(100))</code>），不如 <code>VARCHAR</code> 灵活。能用 <code>VARCHAR</code> 就别用 <code>TEXT</code>。</p><h2 id="四、时间类型" tabindex="-1">四、时间类型 <a class="header-anchor" href="#四、时间类型" aria-label="Permalink to &quot;四、时间类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>特点</th></tr></thead><tbody><tr><td><code>DATETIME</code></td><td>不受时区影响，存什么取什么（8 字节）</td></tr><tr><td><code>TIMESTAMP</code></td><td>受时区影响，存入时转 UTC，取出时按会话时区显示（4 字节）</td></tr></tbody></table><p><code>TIMESTAMP</code> 的时区行为容易踩坑：同一个 <code>TIMESTAMP</code> 值，不同时区的会话查出来显示不一样。存的是 UTC，显示按会话时区。如果应用服务器和数据库时区不一致，<code>TIMESTAMP</code> 字段在不同地方看结果不同。</p><p>大多数业务场景用 <code>DATETIME</code> 更直观——存进去什么就是什么，不随会话时区变。需要自动记录创建/更新时间，配 <code>DEFAULT CURRENT_TIMESTAMP</code> 和 <code>ON UPDATE CURRENT_TIMESTAMP</code>（上一篇建表里那样）。</p><h2 id="五、enum-和-json" tabindex="-1">五、ENUM 和 JSON <a class="header-anchor" href="#五、enum-和-json" aria-label="Permalink to &quot;五、ENUM 和 JSON&quot;">​</a></h2><p><code>ENUM</code> 存固定枚举值：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">env ENUM(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;dev&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;test&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;prod&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NOT NULL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DEFAULT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;test&#39;</span></span></code></pre></div><p>只能取列出的值之一。好处是省空间、值受约束。坏处是<strong>加新值要 <code>ALTER TABLE</code></strong>——加个 <code>staging</code> 环境得改表结构。枚举值固定不变用 ENUM，可能变的用 VARCHAR 加应用层校验。</p><p><code>JSON</code> 类型存结构化数据：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">extra </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JSON</span></span></code></pre></div><p>适合存扩展属性、不固定的配置。但<strong>频繁查询的 key 应该拆成独立列</strong>——JSON 里某个 key 要建索引、要查询，每次都要解析 JSON，慢且不方便。JSON 适合&quot;偶尔看看&quot;的字段，不适合核心查询字段。</p><h2 id="六、null-的陷阱" tabindex="-1">六、NULL 的陷阱 <a class="header-anchor" href="#六、null-的陷阱" aria-label="Permalink to &quot;六、NULL 的陷阱&quot;">​</a></h2><p><code>NULL</code> 在 SQL 里不是空字符串、不是 0——它表示&quot;未知&quot;。这个&quot;未知&quot;有一套特殊的三值逻辑，是很多 bug 的源头。</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 唯一约束里，多个 NULL 不算冲突</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 这张表的 remark 字段有 UNIQUE 约束，可以有多行 remark 为 NULL</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 查询时 NULL 的坑</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> servers </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> remark </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;test&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- remark 为 NULL 的行查不出来！NULL != &#39;test&#39; 的结果是&quot;未知&quot;，不是 true</span></span></code></pre></div><p>判断 NULL 要用 <code>IS NULL</code> / <code>IS NOT NULL</code>，不能用 <code>=</code> / <code>!=</code>。</p><p>原则：<strong>字段如果不需要表达&quot;没有值&quot;，就加 <code>NOT NULL</code> 并给默认值。</strong> 只有确实需要区分&quot;空字符串&quot;和&quot;未知&quot;时才用 NULL。绝大多数字段应该 <code>NOT NULL</code>，少踩三值逻辑的坑。</p><h2 id="七、约束" tabindex="-1">七、约束 <a class="header-anchor" href="#七、约束" aria-label="Permalink to &quot;七、约束&quot;">​</a></h2><p>约束是建表时给字段加的规则，违反就报错。它们在数据库层挡住脏数据，不依赖应用代码：</p><table tabindex="0"><thead><tr><th>约束</th><th>作用</th><th>违反时报错</th></tr></thead><tbody><tr><td><code>PRIMARY KEY</code></td><td>唯一 + 非空</td><td>重复主键报错</td></tr><tr><td><code>UNIQUE</code></td><td>值唯一（允许多个 NULL）</td><td><code>Duplicate entry</code></td></tr><tr><td><code>NOT NULL</code></td><td>不能为空</td><td>插 NULL 报错</td></tr><tr><td><code>DEFAULT</code></td><td>不给值时填默认</td><td>静默填充</td></tr><tr><td><code>FOREIGN KEY</code></td><td>引用完整性（外键）</td><td>删被引用行时阻止或级联</td></tr></tbody></table><p>前四个常用。<code>FOREIGN KEY</code> 要特别说——它保证引用完整性（订单引用的用户不能被删），但生产环境经常不用外键：</p><ul><li>外键带来额外开销（每次写都校验引用）</li><li>删被引用行受限，批量维护麻烦</li><li>引用完整性更适合在应用层保证</li></ul><p>小项目可以用外键兜底，高并发或大规模系统一般去掉外键，靠应用逻辑保证。</p><h2 id="八、约束的取舍" tabindex="-1">八、约束的取舍 <a class="header-anchor" href="#八、约束的取舍" aria-label="Permalink to &quot;八、约束的取舍&quot;">​</a></h2><p>约束不是越多越好。加约束意味着每次写入都校验，有性能开销。但少了约束，脏数据进来了后面清理更痛苦。</p><p>判断标准：</p><ul><li><strong>数据正确性关键的</strong>（主键、唯一、非空）——必加</li><li><strong>业务规则明确的</strong>（状态码范围、环境枚举）——加</li><li><strong>引用关系</strong>——看规模，小项目加，大项目应用层保证</li><li><strong>性能敏感的高频写入</strong>——少加，靠应用校验</li></ul><p>建表时把这些想清楚，比上线后改约束（又是重操作）省事得多。</p><h2 id="类型选好之后" tabindex="-1">类型选好之后 <a class="header-anchor" href="#类型选好之后" aria-label="Permalink to &quot;类型选好之后&quot;">​</a></h2><p>字段类型和约束定了，表结构稳定了。下一步是往表里存数据、查数据——增删改查。下一篇讲。</p>`,47)])])}const E=e(i,[["render",o]]);export{k as __pageData,E as default};
